 1	import type { FC } from 'react';
 2	import { DetailsItem } from 'src/components/DetailItems/DetailItem';
 3	import { ModalHOC } from 'src/modules/Providers/modals/ModalHOC/ModalHOC';
 4	import { CredentialsDetailsItem } from 'src/modules/Providers/views/details/components/DetailsSection/components/CredentialsDetailsItem';
 5	import { ExternalManagementLinkDetailsItem } from 'src/modules/Providers/views/details/components/DetailsSection/components/ExternalManagementLinkDetailsItem';
 6	import { TransferNetworkDetailsItem } from 'src/modules/Providers/views/details/components/DetailsSection/components/TransferNetworkDetailsItem';
 7	import { TypeDetailsItem } from 'src/modules/Providers/views/details/components/DetailsSection/components/TypeDetailsItem';
 8	import { URLDetailsItem } from 'src/modules/Providers/views/details/components/DetailsSection/components/URLDetailsItem';
 9	import { getOpenshiftProviderWebUILink } from 'src/modules/Providers/views/details/components/DetailsSection/utils/getOpenshiftProviderWebUILink';
10	import { useForkliftTranslation } from 'src/utils/i18n';
11	
12	import CreatedAtDetailsItem from '@components/DetailItems/CreatedAtDetailItem';
13	import NameDetailsItem from '@components/DetailItems/NameDetailItem';
14	import NamespaceDetailsItem from '@components/DetailItems/NamespaceDetailItem';
15	import OwnerDetailsItem from '@components/DetailItems/OwnerDetailItem';
16	import { DescriptionList } from '@patternfly/react-core';
17	
18	import type { DetailsSectionProps } from './utils/types';
19	
20	const OpenshiftDetailsSection: FC<DetailsSectionProps> = ({ data }) => {
21	  const { t } = useForkliftTranslation();
22	  const { permissions, provider } = data;
23	
24	  if (!provider || !permissions) return null;
25	
26	  return (
27	    <ModalHOC>
28	      <DescriptionList
29	        columnModifier={{
30	          default: '2Col',
31	        }}
32	      >
33	        <TypeDetailsItem resource={provider} />
34	
35	        {/* Avoid displaying the external web ui link for the local cluster */}
36	        {provider?.spec?.url ? (
37	          <ExternalManagementLinkDetailsItem
38	            resource={provider}
39	            canPatch={permissions.canPatch}
40	            webUILinkText={t(`OpenShift web console UI`)}
41	            webUILink={getOpenshiftProviderWebUILink(provider)}
42	          />
43	        ) : (
44	          <DetailsItem title={''} content={''} />
45	        )}
46	
47	        <NameDetailsItem resource={provider} />
48	        <NamespaceDetailsItem resource={provider} />
49	        <URLDetailsItem
50	          resource={provider}
51	          canPatch={permissions.canPatch}
52	          helpContent={t(
53	            'URL of the Openshift Virtualization API endpoint. Empty might be used for the host provider.',
54	          )}
55	        />
56	        <CredentialsDetailsItem resource={provider} />
57	        <CreatedAtDetailsItem resource={provider} />
58	        <TransferNetworkDetailsItem resource={provider} canPatch={permissions.canPatch} />
59	        <OwnerDetailsItem resource={provider} />
60	      </DescriptionList>
61	    </ModalHOC>
62	  );
63	};
64	
65	export default OpenshiftDetailsSection;

